function formatAbbreviatedCurrency(
  value: number,
  divisor: number,
  fractionDigits: number,
  suffix: string
) {
  const sign = value < 0 ? "-" : "";
  return `${sign}$${formatNumberRoundedDown(Math.abs(value) / divisor, fractionDigits)}${suffix}`;
}

const fmt = (n: number) => {
  const abs = Math.abs(n);
  if (abs >= 1e9) return formatAbbreviatedCurrency(n, 1e9, 2, "B");
  if (abs >= 1e6) return formatAbbreviatedCurrency(n, 1e6, 2, "M");
  if (abs >= 1e3) return formatAbbreviatedCurrency(n, 1e3, 1, "K");
  return formatCurrencyFixed(n, 2);
};

const fmtCompact = (n: number) => {
  const abs = Math.abs(n);
  if (abs >= 1e9) return formatAbbreviatedCurrency(n, 1e9, 1, "B");
  if (abs >= 1e6) return formatAbbreviatedCurrency(n, 1e6, 0, "M");
  if (abs >= 1e3) return formatAbbreviatedCurrency(n, 1e3, 0, "K");
  return formatAbbreviatedCurrency(n, 1, 0, "");
};

function getSliderProgress(value: number, min: number, max: number) {
  return ((value - min) / (max - min)) * 100;
}

function rangeSliderStyle(
  progress: number,
  fill = "var(--bg-brand)",
  empty = "var(--bg-tabs)"
): React.CSSProperties {
  return {
    "--range-progress": `${progress}%`,
    "--range-fill": fill,
    "--range-empty": empty,
  } as React.CSSProperties;
}

