interface DistributorData {
  distributorId: string;
  distributorName: string;
  tier: string;
  totalRevenueShare: number;
  totalHistoricalVolume: number;
  inviteeVolume30d: number;
  graduatedInvitees: number;
}

let distributorLeaderboardCache: DistributorData[] | null = null;
let distributorLeaderboardInflight: Promise<DistributorData[]> | null = null;

function stringValue(value: unknown): string {
  return typeof value === "string" || typeof value === "number"
    ? String(value).trim()
    : "";
}

function normalizeIdentity(value: unknown): string {
  return stringValue(value).toLowerCase();
}

function readStoredJson<T>(suffix: string): T | null {
  if (typeof window === "undefined") return null;
  const raw = walletGetItem(suffix);
  if (!raw) return null;
  try {
    return JSON.parse(raw) as T;
  } catch {
    return null;
  }
}

function getConnectedDistributorIdentity(): string {
  const profile = readStoredJson<{ role?: string; brokerId?: string }>(
    "orderlyProfile"
  );
  if (profile?.role === "ambassador") {
    const storedKey = readStoredJson<{ accountId?: string }>("orderlyApiKey");
    const context = readStoredJson<{ accountId?: string }>(
      "orderlyLoginContext"
    );
    return normalizeIdentity(storedKey?.accountId || context?.accountId);
  }
  return normalizeIdentity(profile?.brokerId);
}

function parseDistributorRecord(raw: unknown): DistributorData | null {
  if (!raw || typeof raw !== "object") return null;
  const source = raw as Record<string, unknown>;
  const totalRevenueShare = Number(
    source["Total Revenue Share"] ??
      source.totalRevenueShare ??
      source.total_revenue_share
  );
  const totalHistoricalVolume = Number(
    source["Total Historical Volume"] ??
      source.totalHistoricalVolume ??
      source.total_historical_volume ??
      source["30D Invitee Volume"] ??
      source.inviteeVolume30d ??
      source.invitee_volume_30d
  );
  const inviteeVolume30d = Number(
    source["30D Invitee Volume"] ??
      source.inviteeVolume30d ??
      source.invitee_volume_30d ??
      0
  );
  const graduatedInvitees = Number(
    source["Number of Graduated Invitees"] ??
      source.graduatedInvitees ??
      source.graduated_invitees
  );
  if (
    !Number.isFinite(totalRevenueShare) ||
    !Number.isFinite(totalHistoricalVolume) ||
    !Number.isFinite(inviteeVolume30d) ||
    !Number.isFinite(graduatedInvitees)
  )
    return null;
  return {
    distributorId: stringValue(
      source["Distributor ID"] ?? source.distributorId ?? source.distributor_id
    ),
    distributorName: String(
      source["Distributor Name"] ??
        source.distributorName ??
        source.distributor_name ??
        ""
    ),
    tier: String(
      source["Fee Tier"] ?? source.tier ?? source.feeTier ?? "Public"
    ),
    totalRevenueShare,
    totalHistoricalVolume,
    inviteeVolume30d,
    graduatedInvitees,
  };
}

function getDistributorDedupeKey(row: DistributorData): string {
  const distributorId = normalizeIdentity(row.distributorId);
  if (distributorId) return `id:${distributorId}`;
  const distributorName = normalizeIdentity(row.distributorName);
  return distributorName ? `name:${distributorName}` : "";
}

function isPreferredDistributorRecord(
  candidate: DistributorData,
  current: DistributorData
): boolean {
  if (candidate.totalRevenueShare !== current.totalRevenueShare)
    return candidate.totalRevenueShare > current.totalRevenueShare;
  if (candidate.totalHistoricalVolume !== current.totalHistoricalVolume)
    return candidate.totalHistoricalVolume > current.totalHistoricalVolume;
  return candidate.graduatedInvitees > current.graduatedInvitees;
}

function dedupeDistributorRows(rows: DistributorData[]): DistributorData[] {
  const keyedRows = new Map<string, DistributorData>();
  const unkeyedRows: DistributorData[] = [];

  for (const row of rows) {
    const key = getDistributorDedupeKey(row);
    if (!key) {
      unkeyedRows.push(row);
      continue;
    }

    const existing = keyedRows.get(key);
    if (!existing || isPreferredDistributorRecord(row, existing))
      keyedRows.set(key, row);
  }

  return [...keyedRows.values(), ...unkeyedRows];
}

function loadDistributorLeaderboard() {
  if (distributorLeaderboardCache)
    return Promise.resolve(distributorLeaderboardCache);
  if (distributorLeaderboardInflight) return distributorLeaderboardInflight;

  distributorLeaderboardInflight = fetch(CONFIG.API_URL, {
    headers: {
      accept: "application/json",
    },
  })
    .then(async response => {
      if (!response.ok)
        throw new Error("Failed to fetch distributor leaderboard");
      const payload = await response.json();
      if (!Array.isArray(payload))
        throw new Error("Invalid distributor leaderboard payload");
      const parsedRows = payload
        .map(parseDistributorRecord)
        .filter((row): row is DistributorData => row !== null);
      const rows = dedupeDistributorRows(parsedRows).sort(
        (a, b) => b.totalRevenueShare - a.totalRevenueShare
      );
      distributorLeaderboardCache = rows;
      return rows;
    })
    .finally(() => {
      distributorLeaderboardInflight = null;
    });

  return distributorLeaderboardInflight;
}

