    let cancelled = false;

    async function loadLeaderboard() {
      try {
        setLoading(true);
        setLeaderboardError(false);
        const rows = await loadDistributorLeaderboard();
        if (!cancelled) setLeaderboardData(rows);
      } catch {
        if (!cancelled) {
          setLeaderboardData([]);
          setLeaderboardError(true);
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    void loadLeaderboard();
    return () => {
      cancelled = true;
    };
